    <!-- 隐藏数据区：存储原始<Options>块（由正则$1替换） -->
    <div id="amberRawData">$1</div>

    <!-- 卡片主体 -->
    <div class="amber-card">
        <div class="amber-status">

            <span>🐚 梦境走向 · 推演中</span>
        </div>
        <div class="amber-header">
            <div class="amber-title">
                🌿 琥珀回响
                <span>下一步</span>
            </div>
            <div class="amber-meta">

            </div>
        </div>
        <div class="options-container" id="optionsContainer"></div>
    </div>

    <div class="amber-toast" id="amberToast">✓ 已复制</div>

    <script>
        (function() {
            const rawDiv = document.getElementById('amberRawData');
            if (!rawDiv) return;
            const rawText = rawDiv.innerText.trim();
            if (!rawText) return;

            const o1Match = rawText.match(/〔O1〕\s*([\s\S]*?)\s*(?=〔O2〕|$)/);
            const o2Match = rawText.match(/〔O2〕\s*([\s\S]*?)\s*(?=〔O3〕|$)/);
            const o3Match = rawText.match(/〔O3〕\s*([\s\S]*?)\s*(?=〔O4〕|$)/);
            const o4Match = rawText.match(/〔O4〕\s*([\s\S]*?)\s*$/);

            const options = [
                o1Match ? o1Match[1].trim() : '',
                o2Match ? o2Match[1].trim() : '',
                o3Match ? o3Match[1].trim() : '',
                o4Match ? o4Match[1].trim() : ''
            ];

            const container = document.getElementById('optionsContainer');
            const toast = document.getElementById('amberToast');
            if (!container || !toast) return;

            container.innerHTML = '';

            let toastTimer = null;
            function showToast(msg) {
                if (toastTimer) clearTimeout(toastTimer);
                toast.textContent = msg || '✓ 已复制';
                toast.classList.add('show');
                toastTimer = setTimeout(() => {
                    toast.classList.remove('show');
                    toastTimer = null;
                }, 1500);
            }

            function copyText(text) {
                if (!text) {
                    showToast('❌ 内容为空');
                    return;
                }
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(text)
                        .then(() => showToast('✓ 已复制'))
                        .catch(() => fallbackCopy(text));
                } else {
                    fallbackCopy(text);
                }
            }

            function fallbackCopy(text) {
                const textarea = document.createElement('textarea');
                textarea.value = text;
                textarea.style.position = 'fixed';
                textarea.style.opacity = '0';
                document.body.appendChild(textarea);
                textarea.select();
                textarea.setSelectionRange(0, text.length);
                try {
                    const success = document.execCommand('copy');
                    showToast(success ? '✓ 已复制' : '❌ 复制失败');
                } catch (err) {
                    showToast('❌ 复制失败');
                }
                document.body.removeChild(textarea);
            }

            const tags = ['O1', 'O2', 'O3', 'O4'];
            options.forEach((optText, index) => {
                const btn = document.createElement('div');
                btn.className = 'option-btn';

                const tagSpan = document.createElement('span');
                tagSpan.className = 'option-tag';
                tagSpan.textContent = tags[index];

                const descSpan = document.createElement('span');
                descSpan.className = 'option-desc';
                descSpan.textContent = optText || '（空选项）';

                btn.appendChild(tagSpan);
                btn.appendChild(descSpan);

                btn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    const text = descSpan.textContent.trim();
                    if (text === '（空选项）' || text === '') {
                        showToast('❌ 无内容');
                        return;
                    }
                    copyText(text);
                });

                container.appendChild(btn);
            });
        })();
    </script>
